import { AxiosError, AxiosPromise, AxiosResponse } from 'axios';

import { User, UserController } from 'controllers';

import * as Types from './types';

//<editor-fold desc="Fetch user data">
const fetchUserDataStart = (): Types.FetchUserDataActionStart => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__START,
  apiRequest: (): AxiosPromise<{ user?: User }> => UserController.fetchUserInfo(),
  followupActions: { SUCCESS: fetchUserDataSuccess, FAILURE: fetchUserDataFailure },
});

const fetchUserDataSuccess = (
  response: AxiosResponse<{ user?: User }>,
): Types.FetchUserDataActionSuccess => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__SUCCESS,
  payload: response,
});

const fetchUserDataFailure = (error: AxiosError): Types.FetchUserDataActionFailure => ({
  type: Types.UserActionTypes.FETCH_USER_DATA__FAILURE,
  error,
});
//</editor-fold>

//<editor-fold desc="Login user">
const loginUserStart = (discordCode: string): Types.LoginUserActionStart => ({
  type: Types.UserActionTypes.LOGIN_USER__START,
  discordCode,
});

const loginUserSuccess = (response: AxiosResponse<User>): Types.LoginUserActionSuccess => ({
  type: Types.UserActionTypes.LOGIN_USER__SUCCESS,
  payload: response,
});

const loginUserFailure = (error: AxiosError): Types.LoginUserActionFailure => ({
  type: Types.UserActionTypes.LOGIN_USER__FAILURE,
  error,
});
//</editor-fold>

//<editor-fold desc="Logout user">
const logoutUserStart = (): Types.LogoutUserActionStart => ({
  type: Types.UserActionTypes.LOGOUT_USER__START,
  apiRequest: (): AxiosPromise<unknown> => UserController.logoutUser(),
  followupActions: { SUCCESS: logoutUserSuccess, FAILURE: logoutUserFailure },
});

const logoutUserSuccess = (response: AxiosResponse<unknown>): Types.LogoutUserActionSuccess => ({
  type: Types.UserActionTypes.LOGOUT_USER__SUCCESS,
  payload: response,
});

const logoutUserFailure = (error: AxiosError): Types.LogoutUserActionFailure => ({
  type: Types.UserActionTypes.LOGOUT_USER__FAILURE,
  error,
});
//</editor-fold>

const userNotAuthorized = (): Types.UserNotAuthorizedAction => ({
  type: Types.UserActionTypes.USER_NOT_AUTHORIZED,
});

export const actions = {
  fetchUserDataStart,
  fetchUserDataSuccess,
  fetchUserDataFailure,
  loginUserStart,
  loginUserSuccess,
  loginUserFailure,
  logoutUserStart,
  logoutUserSuccess,
  logoutUserFailure,
  userNotAuthorized,
};
