import { AxiosPromise } from 'axios';
import { Axios, AxiosService } from 'services';

import { User } from './types';

class UserControllerClass {
  constructor(private APIService: AxiosService) {}

  fetchUserInfo = (): AxiosPromise<{ user?: User }> => {
    return this.APIService.get('user');
  };

  loginUser = (code: string): AxiosPromise<User> => {
    return this.APIService.post('discord', { code });
  };

  logoutUser = (): AxiosPromise<unknown> => {
    return this.APIService.post('signout', {}, { headers: { Accept: 'text/plain' } });
  };
}

export const UserController = new UserControllerClass(Axios);
