import React from 'react';
import merge from 'classnames';

import { DISCORD_AUTH_URL } from 'variables';
import { ArrowIcon, Button, Image, UserIcon } from 'components';

import { Hamburger } from '../Hamburger';
import { Props } from './types';
import styles from './NavigationBar.module.scss';

export const NavigationBar: React.FC<Props> = props => {
  const { isMenuOpened, openMenu, closeMenu, userInfo, logoutUser } = props;
  const onLoginButtonClick = () => {
    closeMenu();
    window.location.replace(DISCORD_AUTH_URL);
  };

  return (
    <React.Fragment>
      <nav className={merge(styles.nav, styles.no_desktop, { [styles.opened]: isMenuOpened })}>
        <div className={styles.header}>
          <span>{userInfo ? userInfo.name : 'Guest'}</span>
          <Hamburger active={true} onClick={closeMenu} />
        </div>

        {userInfo ? (
          <Button color="transparent" className={styles.big_button} onClick={logoutUser}>
            <span>Log Out</span>
            <ArrowIcon direction="right" className={styles.icon} color="white" />
          </Button>
        ) : (
          <Button color="transparent" className={styles.big_button} onClick={onLoginButtonClick}>
            <span>Log In</span>
            <UserIcon className={styles.icon} color="white" />
          </Button>
        )}
      </nav>

      <nav className={merge(styles.nav, styles.desktop)}>
        {userInfo ? (
          <React.Fragment>
            {userInfo.admin && (
              <Button color="transparent" className={styles.big_button} onClick={() => {}}>
                Manage
              </Button>
            )}

            <div className={styles.user_info}>
              <span>{userInfo.name}</span>
              <Button color="transparent" className={styles.small_button} onClick={logoutUser}>
                Log Out
              </Button>
            </div>

            <Image src={userInfo.avatar} alt="Your Discord avatar" className={styles.user_avatar} />
          </React.Fragment>
        ) : (
          <Button color="transparent" className={styles.big_button} onClick={onLoginButtonClick}>
            Log In
          </Button>
        )}
      </nav>

      <div
        className={merge(styles.backdrop, { [styles.opened]: isMenuOpened })}
        onClick={closeMenu}
      />

      <Hamburger active={false} onClick={openMenu} />
    </React.Fragment>
  );
};
